mapper.select:
SELECT
	b.id createId
FROM sys_eve_user b
	INNER JOIN sys_eve_user_staff c ON b.id = c.user_id
	INNER JOIN sys_eve_user_staff_time d ON c.id = d.staff_id AND d.check_work_time_id = #{timeId}


		INNER JOIN tenant_user e ON e.staff_id = c.id AND e.tenant_id = #{tenantId}

WHERE b.user_lock = '0'


		AND d.tenant_id = #{tenantId}

		AND (e.state != 2 OR e.quit_time IS NULL OR LENGTH(e.quit_time) = 0 OR e.quit_time >= #{yesterdayTime})



		AND c.state = '1'



AND b.id NOT IN (
	SELECT b2.id
	FROM check_work a
	INNER JOIN sys_eve_user b2 ON b2.id = a.create_id
	INNER JOIN sys_eve_user_staff c2 ON b2.id = c2.user_id
	INNER JOIN sys_eve_user_staff_time d2 ON c2.id = d2.staff_id
		AND d2.check_work_time_id = #{timeId}
		AND a.time_id = d2.check_work_time_id
	WHERE a.check_date = #{yesterdayTime}

		AND a.tenant_id = #{tenantId} AND d2.tenant_id = #{tenantId}

)

SELECT a.id
FROM check_work a
WHERE a.check_date = #{checkDate}
AND a.time_id = #{schedulingTimeId}
AND (a.clock_out IS NULL OR LENGTH(a.clock_out) = 0)
AND a.clock_in IS NOT NULL AND LENGTH(a.clock_in) > 0

	AND a.tenant_id = #{tenantId}

mapper.update:
update check_work

	state = #{state},
	clock_out_state = #{clockOutState},
	work_hours = #{workHours}

WHERE id = #{id}

	AND tenant_id = #{tenantId}

mapper.select:
		SELECT
			a.id,
			IFNULL(a.clock_in, '') clockIn,
			IFNULL(a.clock_out, '') clockOut,
            a.clock_in_source clockInSource,
            a.clock_out_source clockOutSource
		FROM
			check_work a
		WHERE 
			a.check_date = #{checkDate}
		AND a.create_id = #{createId}
		AND a.time_id = #{timeId}

			AND a.tenant_id = #{tenantId}

SELECT a.id, a.check_date checkDate, IFNULL(a.clock_in, '') clockIn, IFNULL(a.clock_out, '') clockOut, a.state, a.clock_in_longitude clockInLongitude, a.clock_in_latitude clockInLatitude, a.clock_in_address clockInAddress, a.clock_in_source clockInSource, a.clock_out_longitude clockOutLongitude, a.clock_out_latitude clockOutLatitude, a.clock_out_address clockOutAddress, a.clock_out_source clockOutSource, a.clock_out_state clockOutState, a.clock_in_state clockInState, a.work_hours workHours, a.time_id timeId, a.create_id createId, IFNULL(c.id, '') appealSuccessId FROM check_work a LEFT JOIN check_work_appeal c ON a.id = c.work_id AND c.state = #{state} WHERE a.create_id = #{createId}
AND a.tenant_id = #{tenantId}
ORDER BY a.check_date DESC

SELECT a.id, a.check_date name, a.time_id timeId, a.state FROM check_work a WHERE a.create_id = #{userId} AND a.id NOT in (SELECT b.work_id FROM check_work_appeal b WHERE b.state = #{state})
#{checkState}
AND a.tenant_id = #{tenantId}
ORDER BY a.check_date DESC

SELECT concat(a.id, 'a') id, a.time_id timeId, '上班时间' title, a.check_date 'start', a.check_date 'end', IFNULL(a.clock_in,'未打卡') clockIn, true allday, CASE WHEN a.clock_in_state=3 THEN '#ff3300' WHEN a.clock_in_state=2 THEN '#ff9900' WHEN a.clock_in_state=1 THEN '#32cd99' ELSE '#ffffff' END backgroundColor, CASE WHEN a.clock_in_state=3 THEN '未打卡' WHEN a.clock_in_state=2 THEN '迟到' WHEN a.clock_in_state=1 THEN '正常' ELSE '未打卡' END stateName, '1' showBg, false editable, a.clock_in_state state, '10' type FROM check_work a WHERE a.create_id = #{userId} AND (a.time_id = #{timeId} OR a.time_id = '-')
#{month}
AND a.tenant_id = #{tenantId}
UNION ALL SELECT concat(a.id, 'b') id, a.time_id timeId, '下班时间' title, a.check_date 'start', a.check_date 'end', IFNULL(a.clock_out,'未打卡') clockIn, true allday, CASE WHEN a.clock_out_state=3 THEN '#ff3300' WHEN a.clock_out_state=2 THEN '#ff9900' WHEN a.clock_out_state=1 THEN '#32cd99' ELSE '#ffffff' END backgroundColor, CASE WHEN a.clock_out_state=3 THEN '未打卡' WHEN a.clock_out_state=2 THEN '早退' WHEN a.clock_out_state=1 THEN '正常' ELSE '未打卡' END stateName, '1' showBg, false editable, a.clock_out_state state, '10' type FROM check_work a WHERE a.create_id = #{userId} AND (a.time_id = #{timeId} OR a.time_id = '-')
#{month}
AND a.tenant_id = #{tenantId}

mapper.sql:

WHERE cw.check_date = #{day}


    AND b.user_name LIKE '%${userName}%'


    AND cw.tenant_id = #{tenantId}


    AND cw.time_id = #{timeId}

when.foreach:
SELECT
    #{day} checkDay,

    (SELECT COUNT(1) FROM check_work cw

        AND cw.state = 1
    ) fullTime,

    (SELECT COUNT(1) FROM check_work cw

        AND cw.state = 2
    ) absenteeism,

    (SELECT COUNT(1) FROM check_work cw

        AND cw.state = 3
    ) lackTime,

    (SELECT COUNT(1) FROM check_work cw

        AND cw.clock_in_state = 2
    ) late,

    (SELECT COUNT(1) FROM check_work cw

        AND cw.clock_out_state = 2
    ) leaveEarly,

    (SELECT COUNT(1) FROM check_work cw

        AND ((cw.clock_out IS NOT NULL AND cw.clock_in IS NULL) OR (cw.clock_out IS NULL AND cw.clock_in IS NOT NULL))
    ) missing

mapper.select:
SELECT a.id, a.check_date checkDate, a.time_id timeId,
CASE WHEN a.time_id = '-' THEN '加班' ELSE IFNULL(t.name, '') END timeName, IFNULL(a.clock_in, '') clockIn, IFNULL(a.clock_out, '') clockOut, a.state, a.clock_out_state clockOutState, a.clock_in_state clockInState, a.work_hours workHours, a.clock_in_source clockInSource, a.clock_out_source clockOutSource, IFNULL(ap.state, '') appealState, a.create_id createId FROM check_work a LEFT JOIN check_work_time t ON a.time_id = t.id LEFT JOIN check_work_appeal ap ON a.id = ap.work_id
AND ap.tenant_id = #{tenantId}
INNER JOIN sys_eve_user_staff b ON a.create_id = b.user_id
AND a.create_id = #{userId}
AND a.check_date = #{day}
AND a.check_date >= #{startTime} AND #{endTime} >= a.check_date
AND a.time_id = #{timeId}
AND a.tenant_id = #{tenantId}
AND b.user_name LIKE '%${userName}%'
ORDER BY a.check_date ASC, a.create_id ASC
